package log

import (
	"fmt"
	"reflect"
	"runtime"
	"strings"

	"github.com/sirupsen/logrus"
)

// WindowsLineEndingHook is a logrus hook that normalizes line endings to CRLF on Windows
type WindowsLineEndingHook struct {
	// Only enabled on Windows
	enabled bool
}

// NewWindowsLineEndingHook creates a new WindowsLineEndingHook
func NewWindowsLineEndingHook() *WindowsLineEndingHook {
	return &WindowsLineEndingHook{
		enabled: runtime.GOOS == "windows",
	}
}

// Levels returns the log levels this hook applies to
func (h *WindowsLineEndingHook) Levels() []logrus.Level {
	return logrus.AllLevels
}

// Fire processes the log entry and normalizes line endings
func (h *WindowsLineEndingHook) Fire(e *logrus.Entry) error {
	if !h.enabled {
		return nil
	}

	// Process the message
	e.Message = normalizeLineEndings(e.Message)

	// Process data fields
	for k, v := range e.Data {
		switch val := v.(type) {
		case string:
			e.Data[k] = normalizeLineEndings(val)
		case fmt.Stringer:
			e.Data[k] = normalizeLineEndings(val.String())
		}
	}

	return nil
}

// normalizeLineEndings converts LF to CRLF, but preserves existing CRLF sequences
func normalizeLineEndings(s string) string {
	if s == "" {
		return s
	}

	var result strings.Builder
	result.Grow(len(s))

	for i := 0; i < len(s); i++ {
		c := s[i]

		if c == '\n' {
			// Check if this is part of an existing \r\n sequence
			if i > 0 && s[i-1] == '\r' {
				// This is already part of \r\n, just write the \n
				result.WriteByte(c)
			} else {
				// This is a standalone \n, convert to \r\n
				result.WriteString("\r\n")
			}
		} else {
			result.WriteByte(c)
		}
	}

	return result.String()
}

